t.script:

let isEditMode = false;
let originalFormData = {};
let activeProfileTab = 'basic';

/* ─── Tab switching ─────────────────────────────────────────── */
function switchProfileTab(tabKey) {
    const previousTab = activeProfileTab;
    activeProfileTab = tabKey;
    if (previousTab && previousTab !== tabKey) {
        clearValidationStates(previousTab);
    }
    document.querySelectorAll('#personalDetailsForm .profile-tab-section').forEach(card => {
        card.style.display = card.getAttribute('data-tab-group') === tabKey ? '' : 'none';
    });
    document.querySelectorAll('#personalDetailsForm .profile-tab-button').forEach(btn => {
        const active = btn.getAttribute('data-tab-target') === tabKey;
        btn.classList.toggle('active', active);
        btn.setAttribute('aria-selected', active ? 'true' : 'false');
    });
}

function syncAndToggleEditMode(sourceCheckbox) {
    document.querySelectorAll('.edit-mode-toggle').forEach(t => {
        t.checked = sourceCheckbox.checked;
    });
    sourceCheckbox.checked ? enableEditMode() : disableEditMode();
}

function enableEditMode() {
    isEditMode = true;
    document.querySelectorAll('.edit-mode-toggle').forEach(t => t.checked = true);
    storeOriginalFormData();
    document.querySelectorAll('#personalDetailsForm input, #personalDetailsForm select').forEach(input => {
        if (input.type === 'hidden') return;
        if (input.classList.contains('edit-mode-toggle')) return;
        if (input.hasAttribute('data-always-readonly')) {
            input.setAttribute('readonly', 'readonly');
            if (input.tagName === 'SELECT' || input.type === 'checkbox') input.setAttribute('disabled', 'disabled');
            input.style.setProperty('pointer-events', 'none');
            input.style.setProperty('background-color', '#e9ecef');
            return;
        }
        input.removeAttribute('readonly');
        input.removeAttribute('disabled');
        input.style.removeProperty('pointer-events');
        input.style.removeProperty('background-color');
    });
    document.getElementById('formActions').style.display = 'block';
    document.getElementById('viewActions').style.display = 'none';
    const disc = document.getElementById('personalDisclaimer');
    if (disc) disc.checked = false;
    const btn = document.getElementById('personalSaveBtn');
    if (btn) { btn.disabled = true; btn.style.opacity = '0.6'; }
    document.querySelectorAll('#personalDetailsForm input, #personalDetailsForm select').forEach(input => {
        input.removeEventListener('input', validateField);
        input.removeEventListener('blur', validateField);
        input.addEventListener('input', validateField);
        input.addEventListener('blur', validateField);
    });
}

function disableEditMode() {
    isEditMode = false;
    document.querySelectorAll('.edit-mode-toggle').forEach(t => t.checked = false);
    document.querySelectorAll('#personalDetailsForm input, #personalDetailsForm select').forEach(input => {
        if (input.type === 'hidden') return;
        if (input.classList.contains('edit-mode-toggle')) return;
        if (input.hasAttribute('data-always-readonly')) {
            input.setAttribute('readonly', 'readonly');
            if (input.tagName === 'SELECT' || input.type === 'checkbox') input.setAttribute('disabled', 'disabled');
            input.style.setProperty('pointer-events', 'none');
            input.style.setProperty('background-color', '#e9ecef');
            return;
        }
        input.setAttribute('readonly', 'readonly');
        if (input.tagName === 'SELECT' || input.type === 'checkbox') input.setAttribute('disabled', 'disabled');
        input.style.removeProperty('pointer-events');
        input.style.removeProperty('background-color');
    });
    document.getElementById('formActions').style.display = 'none';
    document.getElementById('viewActions').style.display = 'block';
    clearValidationStates(activeProfileTab);
    const disc = document.getElementById('personalDisclaimer');
    if (disc) disc.checked = false;
    const btn = document.getElementById('personalSaveBtn');
    if (btn) { btn.disabled = true; btn.style.opacity = '0.6'; }
}

function toggleSaveBtn(checkboxId, btnId) {
    const checked = document.getElementById(checkboxId).checked;
    const btn = document.getElementById(btnId);
    btn.disabled = !checked;
    btn.style.opacity = checked ? '1' : '0.6';
}

function storeOriginalFormData() {
    const formData = new FormData(document.getElementById('personalDetailsForm'));
    originalFormData = {};
    for (let [key, value] of formData.entries()) originalFormData[key] = value;
}

function cancelEdit() {
    for (let [key, value] of Object.entries(originalFormData)) {
        const input = document.querySelector(`[name="${key}"]`);
        if (input) input.value = value;
    }
    clearValidationStates(activeProfileTab);
    disableEditMode();
    showTabMessage(activeProfileTab, 'Changes cancelled.', 'info');
}

function saveAsDraft() {
    const formData = new FormData(document.getElementById('personalDetailsForm'));
    const draftData = {};
    for (let [key, value] of formData.entries()) draftData[key] = value;
    localStorage.setItem('profileDraft', JSON.stringify(draftData));
    showTabMessage(activeProfileTab, 'Profile saved as draft.', 'info');
}

function validateField(event) {
    const field = event.target;
    const parentSection = field.closest('.profile-tab-section');
    if (parentSection && parentSection.getAttribute('data-tab-group') !== activeProfileTab) {
        return true;
    }
    const validationType = field.getAttribute('data-validation');
    let isValid = true;
    let errorMessage = '';
    field.classList.remove('is-valid', 'is-invalid');
    const existingDynamic = field.parentNode.querySelector('.invalid-feedback.dynamic-error');
    if (existingDynamic) existingDynamic.remove();
    const feedback = field.parentNode.querySelector('.invalid-feedback:not(.dynamic-error)');
    if (feedback) { feedback.textContent = ''; feedback.style.display = 'none'; }
    if (validationType && field.value) {
        const val = field.value.trim();
        switch (validationType) {
            case 'email':
                if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(val)) { isValid = false; errorMessage = 'Please enter a valid email address (e.g. name@example.com).'; }
                break;
            case 'phone':
                const phoneCleaned = val.replace(/\s/g, '');
                if (!/^\+?[0-9]+$/.test(phoneCleaned)) { isValid = false; errorMessage = 'Phone number must contain digits only. A leading + is allowed for country code (e.g. +971501234567).'; }
                else { const digitsOnly = phoneCleaned.replace('+', ''); if (digitsOnly.length < 7 || digitsOnly.length > 15) { isValid = false; errorMessage = 'Phone number must be between 7 and 15 digits.'; } }
                break;
            case 'digits-only':
                if (!/^[0-9]+$/.test(val)) { isValid = false; errorMessage = 'This field must contain digits only (no letters or special characters).'; }
                break;
            case 'alphanumeric':
                if (!/^[A-Za-z0-9]+$/.test(val)) { isValid = false; errorMessage = 'This field must contain letters and digits only (no spaces or special characters).'; }
                break;
            case 'emirates-id':
                if (!/^[0-9]{3}-[0-9]{4}-[0-9]{7}-[0-9]{1}$/.test(val)) { isValid = false; errorMessage = 'Emirates ID must be in format: 784-1234-1234567-1'; }
                break;
            case 'aadhar':
                if (!/^[0-9]{12}$/.test(val)) { isValid = false; errorMessage = 'Aadhar number must be exactly 12 digits.'; }
                break;
            case 'pan':
                if (!/^[A-Z]{5}[0-9]{4}[A-Z]{1}$/.test(val.toUpperCase())) { isValid = false; errorMessage = 'PAN must be in format: ABCDE1234F (5 letters, 4 digits, 1 letter).'; }
                break;
            case 'year':
                if (!/^[0-9]{4}$/.test(val)) { isValid = false; errorMessage = 'Please enter a valid 4-digit year (e.g. 2020).'; }
                else { const yr = parseInt(val, 10); const currentYear = new Date().getFullYear(); if (yr < 1900 || yr > currentYear) { isValid = false; errorMessage = `Year must be between 1900 and ${currentYear}.`; } }
                break;
            case 'past-date':
                const pastInput = new Date(val); const todayForPast = new Date(); todayForPast.setHours(0, 0, 0, 0);
                if (isNaN(pastInput.getTime())) { isValid = false; errorMessage = 'Please enter a valid date.'; }
                else if (pastInput > todayForPast) { isValid = false; errorMessage = 'This date cannot be in the future.'; }
                break;
            case 'future-date':
                const futureInput = new Date(val); const todayForFuture = new Date(); todayForFuture.setHours(0, 0, 0, 0);
                if (isNaN(futureInput.getTime())) { isValid = false; errorMessage = 'Please enter a valid date.'; }
                else if (futureInput <= todayForFuture) { isValid = false; errorMessage = 'Expiry date must be a future date. Entered: ' + futureInput.toDateString() + ' | Today: ' + todayForFuture.toDateString(); }
                break;
            case 'required':
                if (!val) { isValid = false; errorMessage = 'This field is required.'; }
                break;
        }
    }
    if (field.value.trim()) {
        if (isValid) { field.classList.add('is-valid'); }
        else {
            field.classList.add('is-invalid');
            if (feedback) { feedback.textContent = errorMessage; feedback.style.display = 'block'; }
            else { const errDiv = document.createElement('div'); errDiv.className = 'invalid-feedback dynamic-error'; errDiv.style.display = 'block'; errDiv.style.color = '#dc3545'; errDiv.style.fontSize = '0.8rem'; errDiv.style.marginTop = '3px'; errDiv.textContent = errorMessage; field.insertAdjacentElement('afterend', errDiv); }
        }
    }
    updateTabErrorBadges();
    return isValid;
}

function updateTabErrorBadges() {
    ['basic', 'professional', 'family', 'education', 'documents'].forEach(tabKey => {
        const tabBtn = document.querySelector(`.profile-tab-button[data-tab-target="${tabKey}"]`);
        if (!tabBtn) return;
        const existing = tabBtn.querySelector('.tab-error-badge');
        if (existing) existing.remove();
        const count = document.querySelectorAll(`.profile-tab-section[data-tab-group="${tabKey}"] .is-invalid`).length;
        if (count > 0) {
            const badge = document.createElement('span');
            badge.className = 'tab-error-badge badge bg-danger ms-1';
            badge.textContent = count;
            tabBtn.appendChild(badge);
        }
    });
}

function clearValidationStates(tabKey) {
    let inputs = [], feedbacks = [], messages = [];
    if (tabKey) {
        const sections = document.querySelectorAll(`.profile-tab-section[data-tab-group="${tabKey}"]`);
        sections.forEach(section => {
            section.querySelectorAll('input, select').forEach(el => inputs.push(el));
            section.querySelectorAll('.invalid-feedback').forEach(el => feedbacks.push(el));
            section.querySelectorAll('.tab-message-box').forEach(el => messages.push(el));
            section.querySelectorAll('.dynamic-error').forEach(el => el.remove());
        });
    } else {
        inputs = document.querySelectorAll('#personalDetailsForm input, #personalDetailsForm select');
        feedbacks = document.querySelectorAll('#personalDetailsForm .invalid-feedback');
        messages = document.querySelectorAll('.tab-message-box');
        document.querySelectorAll('.dynamic-error').forEach(el => el.remove());
    }
    inputs.forEach(input => input.classList.remove('is-valid', 'is-invalid'));
    feedbacks.forEach(el => { el.textContent = ''; el.style.display = 'none'; });
    messages.forEach(el => el.remove());
    updateTabErrorBadges();
}

function showTabMessage(tabKey, text, type) {
    document.querySelectorAll('.tab-message-box').forEach(el => el.remove());
    const firstCard = document.querySelector(`.profile-tab-section[data-tab-group="${tabKey}"]`);
    if (!firstCard) return;
    const alertClass = type === 'success' ? 'alert-success' : type === 'info' ? 'alert-info' : 'alert-danger';
    const icon = type === 'success' ? 'fa-check-circle' : type === 'info' ? 'fa-info-circle' : 'fa-exclamation-triangle';
    const msgDiv = document.createElement('div');
    msgDiv.className = `tab-message-box alert ${alertClass} alert-dismissible fade show mb-3`;
    msgDiv.innerHTML = `<i class="fa ${icon} me-2"></i><span>${text}</span><button type="button" class="btn-close" onclick="this.parentNode.remove()"></button>`;
    firstCard.parentNode.insertBefore(msgDiv, firstCard);
    msgDiv.scrollIntoView({ behavior: 'smooth', block: 'center' });
    setTimeout(() => { if (msgDiv.parentNode) msgDiv.remove(); }, 5000);
}

document.getElementById('personalDetailsForm').addEventListener('submit', function(e) {
    e.preventDefault();
    const disc = document.getElementById('personalDisclaimer');
    if (disc && !disc.checked) {
        showTabMessage(activeProfileTab, 'Please read and accept the Employee Disclaimer before saving.', 'error');
        disc.closest('.alert').style.animation = 'shake 0.35s ease';
        setTimeout(() => disc.closest('.alert').style.animation = '', 400);
        return;
    }
    clearValidationStates(activeProfileTab);
    let isFormValid = true;
    document.querySelectorAll(
        `.profile-tab-section[data-tab-group="${activeProfileTab}"] input[data-validation],
         .profile-tab-section[data-tab-group="${activeProfileTab}"] select[data-validation]`
    ).forEach(input => { if (!validateField({ target: input })) isFormValid = false; });
    updateTabErrorBadges();
    if (!isFormValid) {
        const firstError = document.querySelector(`.profile-tab-section[data-tab-group="${activeProfileTab}"] .is-invalid`);
        if (firstError) { setTimeout(() => { firstError.scrollIntoView({ behavior: 'smooth', block: 'center' }); firstError.focus(); }, 100); }
        showTabMessage(activeProfileTab, 'Please correct the highlighted errors in this tab.', 'error');
        return;
    }
    const toReenable = [];
    document.querySelectorAll('#personalDetailsForm select[disabled], #personalDetailsForm input[type="checkbox"][disabled]').forEach(el => {
        if (!el.hasAttribute('data-always-readonly')) { el.removeAttribute('disabled'); toReenable.push(el); }
    });
    const formData = new FormData(this);
    const csrfToken = document.querySelector('input[name="csrf_token"]').value;
    toReenable.forEach(el => el.setAttribute('disabled', 'disabled'));
    fetch('/my/employee/personal', {
        method: 'POST',
        body: formData,
        headers: { 'X-CSRFToken': csrfToken }
    })
    .then(response => response.json())


    .then(data => {
    if (data.success) {
        disableEditMode();
        localStorage.removeItem('profileDraft');
        if (data.no_change) {
            // Nothing changed — show info message, no reference
            showTabMessage(
                activeProfileTab,
                'No changes were detected. Your profile data is already up to date.',
                'info'
            );
        } else {
            const ref = data.reference || '';
            showTabMessage(
                activeProfileTab,
                ' Your changes have been submitted to HR for review and approval.' +
                (ref ? ' Reference: <strong>' + ref + '</strong>' : '') +
                ' You will receive an email once HR approves or rejects your request.',
                'success'
            );
        }
    } else {
        showTabMessage(activeProfileTab, 'Error: ' + (data.error || 'Unknown error'), 'error');
    }
})




    .catch(error => {
        console.error('Error:', error);
        showTabMessage(activeProfileTab, 'Network error. Please try again.', 'error');
    });
});

document.addEventListener('DOMContentLoaded', function() {
    document.querySelectorAll('#personalDetailsForm .profile-tab-button').forEach(button => {
        button.addEventListener('click', function() { switchProfileTab(this.getAttribute('data-tab-target')); });
    });
    switchProfileTab(activeProfileTab);
    const draftData = localStorage.getItem('profileDraft');
    if (draftData) {
        try {
            const draft = JSON.parse(draftData);
            Object.entries(draft).forEach(([key, value]) => {
                const input = document.querySelector(`[name="${key}"]`);
                if (input && input.type !== 'hidden') input.value = value;
            });
            showTabMessage(activeProfileTab, 'Draft data loaded.', 'info');
        } catch (e) { console.error('Error loading draft:', e); }
    }
});
